{
  "title": "ARIA एट्रिब्यूट्स का उद्देश्य",
  "group": "उन्नत सिमेंटिक HTML",
  "options": [
    {
      "text": "टच डिवाइसेस के लिए मददगार",
      "hint": "यह मुख्य उद्देश्य नहीं है।"
    },
    {
      "text": "एक्सेसिबिलिटी (पहुंच) में सुधार करना",
      "hint": "बिल्कुल सही!"
    },
    {
      "text": "साउंड और प्लेबैक को नियंत्रित करना",
      "hint": "ARIA का ऑडियो कंट्रोल से सीधा संबंध नहीं है।"
    },
    {
      "text": "केवल `<div>` का उपयोग करने के लिए",
      "hint": "यह एक खराब कोडिंग प्रैक्टिस है।"
    }
  ],
  "objectives": [],
  "questionProse": [
    "ARIA एट्रिब्यूट्स का मुख्य उद्देश्य क्या है?"
  ],
  "hintsProse": [],
  "explanationProse": [
    "ARIA (Accessible Rich Internet Applications) एट्रिब्यूट्स स्क्रीन रीडर्स और अन्य सहायक तकनीकों (assistive technologies) के लिए अतिरिक्त संदर्भ (context) प्रदान करके वेब एक्सेसिबिलिटी को बढ़ाते हैं।\n\nएलिमेंट्स का वर्णन करने के लिए इसमें roles, states और properties का उपयोग किया जाता है।"
  ]
}
